'use client';

import { useState, useEffect } from 'react';
import { Subject, getEnrollments, getUsers, getAttendances, User } from '@/utils/storage';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { ArrowLeft, Users, CheckCircle, XCircle, Clock } from 'lucide-react';
import StudentInfoDialog from './StudentInfoDialog';

interface SubjectDetailsProps {
  subject: Subject;
  onBack: () => void;
}

export default function SubjectDetails({ subject, onBack }: SubjectDetailsProps) {
  const [enrolledStudents, setEnrolledStudents] = useState<User[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<User | null>(null);

  useEffect(() => {
    const enrollments = getEnrollments();
    const users = getUsers();
    
    // Only show approved enrollments
    const subjectEnrollments = enrollments.filter(e => 
      e.subjectId === subject.id && e.status === 'approved'
    );
    const studentIds = subjectEnrollments.map(e => e.studentId);
    const students = users.filter(u => studentIds.includes(u.id));
    
    setEnrolledStudents(students);
  }, [subject.id]);

  const getStudentAttendanceStats = (studentId: string) => {
    const attendances = getAttendances();
    const studentAttendances = attendances.filter(
      a => a.studentId === studentId && a.subjectId === subject.id
    );
    
    const present = studentAttendances.filter(a => a.status === 'present').length;
    const late = studentAttendances.filter(a => a.status === 'late').length;
    const absent = studentAttendances.filter(a => a.status === 'absent').length;
    const total = studentAttendances.length;
    
    return { present, late, absent, total };
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white border-b">
        <div className="container mx-auto px-4 py-4">
          <Button variant="ghost" onClick={onBack} className="mb-4">
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back to Dashboard
          </Button>
          <div>
            <h1 className="text-2xl">{subject.name}</h1>
            <p className="text-muted-foreground">{subject.day} • {subject.time}</p>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Users className="w-5 h-5" />
              Enrolled Students ({enrolledStudents.length})
            </CardTitle>
          </CardHeader>
          <CardContent>
            {enrolledStudents.length === 0 ? (
              <div className="text-center py-12 text-muted-foreground">
                No students enrolled yet
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {enrolledStudents.map((student) => {
                  const stats = getStudentAttendanceStats(student.id);
                  return (
                    <Card 
                      key={student.id}
                      className="cursor-pointer hover:shadow-lg transition-shadow"
                      onClick={() => setSelectedStudent(student)}
                    >
                      <CardContent className="pt-6">
                        <div className="flex flex-col space-y-4">
                          <div className="flex items-center gap-3">
                            <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center flex-shrink-0">
                              {student.profilePic ? (
                                <img 
                                  src={student.profilePic} 
                                  alt={student.name}
                                  className="w-full h-full rounded-full object-cover"
                                />
                              ) : (
                                <span className="text-primary text-lg font-semibold">
                                  {student.name.charAt(0)}
                                </span>
                              )}
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="font-medium truncate">{student.name}</p>
                              <p className="text-sm text-muted-foreground">{student.id}</p>
                              <p className="text-xs text-muted-foreground">
                                {student.program} • Year {student.year}
                              </p>
                            </div>
                          </div>
                          
                          <div className="border-t pt-3 space-y-2">
                            <p className="text-xs text-muted-foreground mb-2">Attendance Summary</p>
                            <div className="grid grid-cols-3 gap-2 text-center">
                              <div className="bg-green-50 rounded-lg p-2">
                                <CheckCircle className="w-4 h-4 text-green-600 mx-auto mb-1" />
                                <p className="text-xs font-semibold text-green-700">{stats.present}</p>
                                <p className="text-[10px] text-green-600">Present</p>
                              </div>
                              <div className="bg-yellow-50 rounded-lg p-2">
                                <Clock className="w-4 h-4 text-yellow-600 mx-auto mb-1" />
                                <p className="text-xs font-semibold text-yellow-700">{stats.late}</p>
                                <p className="text-[10px] text-yellow-600">Late</p>
                              </div>
                              <div className="bg-red-50 rounded-lg p-2">
                                <XCircle className="w-4 h-4 text-red-600 mx-auto mb-1" />
                                <p className="text-xs font-semibold text-red-700">{stats.absent}</p>
                                <p className="text-[10px] text-red-600">Absent</p>
                              </div>
                            </div>
                            {stats.total > 0 && (
                              <div className="text-center pt-2 border-t">
                                <p className="text-xs text-muted-foreground">
                                  Attendance Rate: <span className="font-semibold" style={{ color: '#E30613' }}>
                                    {Math.round(((stats.present + stats.late) / stats.total) * 100)}%
                                  </span>
                                </p>
                              </div>
                            )}
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                  );
                })}
              </div>
            )}
          </CardContent>
        </Card>
      </main>

      {selectedStudent && (
        <StudentInfoDialog
          student={selectedStudent}
          subject={subject}
          onClose={() => setSelectedStudent(null)}
        />
      )}
    </div>
  );
}
