'use client';

import { useState, useEffect } from 'react';
import { getEnrollments, getSubjects, getUsers, updateEnrollment, Subject, User, Enrollment } from '@/utils/storage';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { CheckCircle, XCircle, Clock } from 'lucide-react';
import { toast } from 'sonner';

interface PendingEnrollmentsProps {
  teacherId: string;
}

export default function PendingEnrollments({ teacherId }: PendingEnrollmentsProps) {
  const [pendingEnrollments, setPendingEnrollments] = useState<Array<{
    enrollment: Enrollment;
    student: User;
    subject: Subject;
  }>>([]);

  useEffect(() => {
    loadPendingEnrollments();
  }, [teacherId]);

  const loadPendingEnrollments = () => {
    const enrollments = getEnrollments();
    const subjects = getSubjects();
    const users = getUsers();

    // Get teacher's subjects
    const teacherSubjects = subjects.filter(s => s.teacherId === teacherId);
    const teacherSubjectIds = teacherSubjects.map(s => s.id);

    // Get pending enrollments for teacher's subjects
    const pending = enrollments
      .filter(e => e.status === 'pending' && teacherSubjectIds.includes(e.subjectId))
      .map(enrollment => {
        const student = users.find(u => u.id === enrollment.studentId);
        const subject = subjects.find(s => s.id === enrollment.subjectId);
        return { enrollment, student: student!, subject: subject! };
      })
      .filter(item => item.student && item.subject);

    setPendingEnrollments(pending);
  };

  const handleApprove = (enrollmentId: string, studentName: string, subjectName: string) => {
    updateEnrollment(enrollmentId, { status: 'approved' });
    toast.success(`Approved ${studentName}'s enrollment in ${subjectName}`);
    loadPendingEnrollments();
  };

  const handleReject = (enrollmentId: string, studentName: string, subjectName: string) => {
    updateEnrollment(enrollmentId, { status: 'rejected' });
    toast.error(`Rejected ${studentName}'s enrollment in ${subjectName}`);
    loadPendingEnrollments();
  };

  if (pendingEnrollments.length === 0) {
    return (
      <Card>
        <CardContent className="flex flex-col items-center justify-center py-12">
          <Clock className="w-12 h-12 text-muted-foreground mb-4" />
          <p className="text-muted-foreground">No pending enrollment requests</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-4">
      <div>
        <h2 className="text-2xl">Pending Enrollment Requests</h2>
        <p className="text-muted-foreground">Review and approve student enrollment requests</p>
      </div>

      <div className="grid gap-4">
        {pendingEnrollments.map(({ enrollment, student, subject }) => (
          <Card key={enrollment.id}>
            <CardHeader>
              <CardTitle className="text-lg">{student.name}</CardTitle>
              <CardDescription>
                {student.program} {student.year ? `- Year ${student.year}` : ''}
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                <div>
                  <p className="text-sm text-muted-foreground">Subject</p>
                  <p className="font-medium">{subject.name}</p>
                  <p className="text-sm text-muted-foreground">{subject.day} • {subject.time}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Student ID</p>
                  <p className="font-medium">{student.id}</p>
                </div>
                <div className="flex gap-2 pt-2">
                  <Button
                    onClick={() => handleApprove(enrollment.id, student.name, subject.name)}
                    className="flex-1 bg-[#E30613] hover:bg-[#E30613]/90"
                  >
                    <CheckCircle className="w-4 h-4 mr-2" />
                    Approve
                  </Button>
                  <Button
                    onClick={() => handleReject(enrollment.id, student.name, subject.name)}
                    variant="outline"
                    className="flex-1"
                  >
                    <XCircle className="w-4 h-4 mr-2" />
                    Reject
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );
}
