
'use client';

import { useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { toast } from 'sonner';
import { getUsersAction } from '@/app/actions/dbActions';

interface LoginPageProps {
  onSwitchToSignup: () => void;
}

export default function LoginPage({ onSwitchToSignup }: LoginPageProps) {
  const [id, setId] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      // Hardcoded Admin check
      if (id === 'admin' && password === 'ADMIN@2026') {
        const adminUser = {
          id: 'admin',
          name: 'System Administrator',
          email: 'admin@school.edu',
          password: 'ADMIN@2026',
          role: 'admin' as const
        };
        login(adminUser);
        localStorage.setItem('currentUserId', 'admin');
        toast.success(`Welcome back, Admin!`);
        setLoading(false);
        return;
      }

      const users = await getUsersAction();
      const user = users.find(u => u.id === id && u.password === password);
      
      if (user) {
        login(user);
        localStorage.setItem('currentUserId', user.id);
        toast.success(`Welcome back, ${user.name}!`);
      } else {
        toast.error('Invalid USN/EMP or password');
      }
    } catch (error) {
      toast.error('An error occurred during login');
    }

    setLoading(false);
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-muted/30">
      <Card className="w-full max-w-md border-primary/10 shadow-2xl">
        <CardHeader className="space-y-2 text-center">
          <div className="flex justify-center mb-4">
            <div className="w-20 h-20 rounded-2xl flex items-center justify-center bg-primary shadow-lg rotate-3 hover:rotate-0 transition-transform">
              <span className="text-white text-3xl font-black">SMS</span>
            </div>
          </div>
          <CardTitle className="text-3xl font-black text-primary">AttendanceWise</CardTitle>
          <CardDescription>Sign in to your academic portal</CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="id">USN / Employee Number</Label>
              <Input
                id="id"
                type="text"
                placeholder="Enter USN or EMP number"
                value={id}
                onChange={(e) => setId(e.target.value)}
                required
                className="h-12"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="password">Password</Label>
              <Input
                id="password"
                type="password"
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                className="h-12"
              />
            </div>
            <Button 
              type="submit" 
              className="w-full h-12 text-lg font-bold bg-primary hover:bg-primary/90 shadow-md" 
              disabled={loading}
            >
              {loading ? 'Authenticating...' : 'Sign In'}
            </Button>
            <div className="text-center text-sm pt-2">
              <span className="text-muted-foreground">Don't have an account? </span>
              <button
                type="button"
                onClick={onSwitchToSignup}
                className="font-bold hover:underline text-primary"
              >
                Create one now
              </button>
            </div>
            <div className="text-center text-[10px] text-muted-foreground mt-6 p-3 bg-primary/5 rounded-xl border border-primary/10">
              <p className="font-bold mb-1 uppercase tracking-widest">Admin Portal Access</p>
              <p>ID: admin / PW: ADMIN@2026</p>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}
