'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { getSubjects, getEnrollments, Subject } from '../../utils/storage';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card';
import { Button } from '../ui/button';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '../ui/tabs';
import { BookOpen, Calendar, LogOut, UserCircle, School } from 'lucide-react';
import EnrollSubjectDialog from './EnrollSubjectDialog';
import StudentCalendar from './StudentCalendar';
import SubjectDetailsStudent from './SubjectDetailsStudent';
import ProfilePage from '../profile/ProfilePage';

export default function StudentDashboard() {
  const { user, logout } = useAuth();
  const [enrolledSubjects, setEnrolledSubjects] = useState<Subject[]>([]);
  const [selectedSubject, setSelectedSubject] = useState<Subject | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showProfile, setShowProfile] = useState(false);

  useEffect(() => {
    loadEnrolledSubjects();
  }, [user]);

  const loadEnrolledSubjects = () => {
    const enrollments = getEnrollments();
    const subjects = getSubjects();
    
    // Only show approved enrollments
    const myEnrollments = enrollments.filter(e => 
      e.studentId === user?.id && e.status === 'approved'
    );
    const mySubjects = subjects.filter(s => 
      myEnrollments.some(e => e.subjectId === s.id)
    );
    
    setEnrolledSubjects(mySubjects);
  };

  if (showProfile) {
    return <ProfilePage onBack={() => setShowProfile(false)} />;
  }

  if (selectedSubject) {
    return (
      <SubjectDetailsStudent 
        subject={selectedSubject} 
        onBack={() => setSelectedSubject(null)} 
      />
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white border-b sticky top-0 z-10 shadow-sm">
        <div className="container mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div 
              className="w-12 h-12 rounded-xl flex items-center justify-center bg-primary shadow-lg shadow-primary/20"
            >
              <School className="text-white h-7 w-7" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-primary leading-tight">Student Portal</h1>
              <p className="text-[10px] uppercase font-bold text-muted-foreground tracking-widest">{user?.name}</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <Button variant="outline" onClick={() => setShowProfile(true)} className="hover:text-primary hover:bg-accent border-primary/20">
              <UserCircle className="w-4 h-4 mr-2" />
              Profile
            </Button>
            <Button variant="outline" onClick={logout} className="hover:text-primary hover:bg-accent border-primary/20">
              <LogOut className="w-4 h-4 mr-2" />
              Logout
            </Button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 max-w-6xl">
        <div className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-6">
          <div>
            <h2 className="text-4xl font-black tracking-tight mb-2">My Academic Life</h2>
            <p className="text-muted-foreground font-medium text-lg italic">Welcome back to your dashboard, {user?.name?.split(' ')[0]}!</p>
          </div>
          <EnrollSubjectDialog onEnrolled={loadEnrolledSubjects} />
        </div>

        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList className="grid w-full grid-cols-2 mb-8 max-w-md bg-white border">
            <TabsTrigger value="dashboard" className="data-[state=active]:text-primary data-[state=active]:font-bold">
              <BookOpen className="w-4 h-4 mr-2" />
              My Subjects
            </TabsTrigger>
            <TabsTrigger value="calendar" className="data-[state=active]:text-primary data-[state=active]:font-bold">
              <Calendar className="w-4 h-4 mr-2" />
              Weekly Schedule
            </TabsTrigger>
          </TabsList>

          <TabsContent value="dashboard" className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {enrolledSubjects.map((subject) => (
                <Card 
                  key={subject.id} 
                  className="cursor-pointer hover:shadow-2xl transition-all border-primary/5 hover:border-primary/30 group relative overflow-hidden h-full flex flex-col"
                  onClick={() => setSelectedSubject(subject)}
                >
                  <div className="h-2 bg-primary w-full" />
                  <CardHeader className="pb-4">
                    <CardTitle className="text-2xl font-black group-hover:text-primary transition-colors">{subject.name}</CardTitle>
                    <CardDescription className="font-bold flex items-center gap-1.5 text-muted-foreground uppercase text-[10px] tracking-widest">
                      <Calendar className="h-3 w-3 text-primary" /> {subject.day} <span className="text-primary">•</span> {subject.time}
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="flex-1 flex flex-col justify-end">
                    <div className="pt-4 border-t border-primary/5 mt-auto">
                      <p className="text-xs font-bold uppercase text-muted-foreground tracking-widest mb-1">Instructor</p>
                      <span className="font-bold text-lg">{subject.teacherName}</span>
                    </div>
                  </CardContent>
                </Card>
              ))}
              
              {enrolledSubjects.length === 0 && (
                <Card className="col-span-full border-dashed border-2 bg-accent/20">
                  <CardContent className="flex flex-col items-center justify-center py-20">
                    <BookOpen className="w-16 h-16 text-primary/20 mb-6" />
                    <h3 className="text-2xl font-bold mb-2">No active subjects found</h3>
                    <p className="text-muted-foreground max-w-sm text-center mb-8">Ready to start your academic journey? Click the button above to enroll in your first subject.</p>
                  </CardContent>
                </Card>
              )}
            </div>
          </TabsContent>

          <TabsContent value="calendar" className="animate-in fade-in slide-in-from-bottom-2 duration-300">
            <StudentCalendar subjects={enrolledSubjects} />
          </TabsContent>
        </Tabs>
      </main>
    </div>
  );
}
