'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { getUsers, getSubjects, getEnrollments, User, Subject } from '../../utils/storage';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../ui/card';
import { Button } from '../ui/button';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '../ui/tabs';
import { Users, BookOpen, LogOut, GraduationCap, School } from 'lucide-react';

export default function AdminDashboard() {
  const { logout } = useAuth();
  const [teachers, setTeachers] = useState<User[]>([]);
  const [students, setStudents] = useState<User[]>([]);
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [selectedTeacher, setSelectedTeacher] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('overview');

  useEffect(() => {
    loadData();
  }, []);

  const loadData = () => {
    const users = getUsers();
    setTeachers(users.filter(u => u.role === 'teacher'));
    setStudents(users.filter(u => u.role === 'student'));
    setSubjects(getSubjects());
  };

  const getSubjectsByTeacher = (teacherId: string) => {
    return subjects.filter(s => s.teacherId === teacherId);
  };

  const getEnrollmentCount = (subjectId: string) => {
    const enrollments = getEnrollments();
    return enrollments.filter(e => e.subjectId === subjectId).length;
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white border-b sticky top-0 z-10 shadow-sm">
        <div className="container mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div 
              className="w-12 h-12 rounded-xl flex items-center justify-center bg-primary"
            >
              <School className="text-white h-7 w-7" />
            </div>
            <div>
              <h1 className="text-xl font-bold text-primary leading-tight">Admin Portal</h1>
              <p className="text-[10px] uppercase font-bold text-muted-foreground tracking-widest">System Management</p>
            </div>
          </div>
          <Button variant="outline" onClick={logout} className="hover:text-primary hover:bg-accent border-primary/20">
            <LogOut className="w-4 h-4 mr-2" />
            Logout
          </Button>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 max-w-6xl">
        <Tabs value={activeTab} onValueChange={setActiveTab}>
          <TabsList className="grid w-full grid-cols-3 mb-8 max-w-2xl bg-white border">
            <TabsTrigger value="overview" className="data-[state=active]:text-primary data-[state=active]:font-bold">
              <BookOpen className="w-4 h-4 mr-2" />
              Overview
            </TabsTrigger>
            <TabsTrigger value="teachers" className="data-[state=active]:text-primary data-[state=active]:font-bold">
              <GraduationCap className="w-4 h-4 mr-2" />
              Teachers
            </TabsTrigger>
            <TabsTrigger value="students" className="data-[state=active]:text-primary data-[state=active]:font-bold">
              <Users className="w-4 h-4 mr-2" />
              Students
            </TabsTrigger>
          </TabsList>

          <TabsContent value="overview" className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <Card className="border-primary/5 hover:border-primary/20 transition-all">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2 text-sm uppercase tracking-wider text-muted-foreground">
                    <GraduationCap className="w-5 h-5 text-primary" />
                    Teachers
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-4xl font-bold">{teachers.length}</p>
                  <p className="text-xs text-muted-foreground mt-1 font-medium">Active teaching staff</p>
                </CardContent>
              </Card>

              <Card className="border-primary/5 hover:border-primary/20 transition-all">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2 text-sm uppercase tracking-wider text-muted-foreground">
                    <Users className="w-5 h-5 text-primary" />
                    Students
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-4xl font-bold">{students.length}</p>
                  <p className="text-xs text-muted-foreground mt-1 font-medium">Registered students</p>
                </CardContent>
              </Card>

              <Card className="border-primary/5 hover:border-primary/20 transition-all">
                <CardHeader>
                  <CardTitle className="flex items-center gap-2 text-sm uppercase tracking-wider text-muted-foreground">
                    <BookOpen className="w-5 h-5 text-primary" />
                    Subjects
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-4xl font-bold">{subjects.length}</p>
                  <p className="text-xs text-muted-foreground mt-1 font-medium">Total class offerings</p>
                </CardContent>
              </Card>
            </div>

            <Card className="border-primary/10 shadow-md">
              <CardHeader className="bg-primary/5 border-b">
                <CardTitle className="text-lg font-bold">Comprehensive Subject Catalog</CardTitle>
                <CardDescription>Overview of all academic sessions currently in the system</CardDescription>
              </CardHeader>
              <CardContent className="pt-6">
                {subjects.length === 0 ? (
                  <div className="text-center py-20 bg-accent/20 rounded-xl border-2 border-dashed border-primary/10">
                    <BookOpen className="h-12 w-12 text-primary/20 mx-auto mb-4" />
                    <p className="text-muted-foreground font-medium">No subjects found in the database</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {subjects.map((subject) => (
                      <div key={subject.id} className="p-5 border rounded-xl hover:bg-primary/5 transition-all group">
                        <div className="flex items-start justify-between">
                          <div className="flex-1">
                            <h4 className="font-bold text-lg group-hover:text-primary transition-colors">{subject.name}</h4>
                            <div className="space-y-1 mt-2">
                              <p className="text-sm text-muted-foreground flex items-center gap-1.5">
                                <GraduationCap className="h-3.5 w-3.5 text-primary" /> {subject.teacherName}
                              </p>
                              <p className="text-sm text-muted-foreground flex items-center gap-1.5">
                                <School className="h-3.5 w-3.5 text-primary" /> {subject.day} • {subject.time}
                              </p>
                            </div>
                          </div>
                          <div className="text-right">
                            <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Enrolled</p>
                            <p className="text-2xl font-black text-primary">{getEnrollmentCount(subject.id)}</p>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="teachers" className="space-y-6">
            <div className="flex items-center justify-between">
              <div>
                <h2 className="text-2xl font-bold">Academic Staff</h2>
                <p className="text-muted-foreground">Detailed directory of all registered teachers</p>
              </div>
            </div>

            {selectedTeacher ? (
              <TeacherDetailsView 
                teacher={selectedTeacher} 
                subjects={getSubjectsByTeacher(selectedTeacher.id)}
                onBack={() => setSelectedTeacher(null)}
              />
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {teachers.map((teacher) => (
                  <Card 
                    key={teacher.id}
                    className="cursor-pointer hover:shadow-xl transition-all border-primary/5 group overflow-hidden"
                    onClick={() => setSelectedTeacher(teacher)}
                  >
                    <div className="h-2 bg-primary w-full" />
                    <CardContent className="pt-8">
                      <div className="flex flex-col items-center text-center space-y-4">
                        <div className="w-20 h-20 rounded-full bg-primary/10 flex items-center justify-center border-4 border-white shadow-md">
                          {teacher.profilePic ? (
                            <img 
                              src={teacher.profilePic} 
                              alt={teacher.name}
                              className="w-full h-full rounded-full object-cover"
                            />
                          ) : (
                            <GraduationCap className="w-10 h-10 text-primary" />
                          )}
                        </div>
                        <div>
                          <p className="font-bold text-lg group-hover:text-primary transition-colors">{teacher.name}</p>
                          <p className="text-xs font-bold text-muted-foreground uppercase tracking-widest mt-1">ID: {teacher.id}</p>
                        </div>
                        <div className="pt-4 border-t w-full flex justify-between items-center px-4">
                          <span className="text-xs font-bold text-muted-foreground uppercase">Subjects</span>
                          <span className="font-black text-primary">{getSubjectsByTeacher(teacher.id).length}</span>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
                
                {teachers.length === 0 && (
                  <Card className="col-span-full border-dashed border-2 bg-muted/20">
                    <CardContent className="flex flex-col items-center justify-center py-20">
                      <GraduationCap className="w-16 h-16 text-primary/20 mb-4" />
                      <p className="text-muted-foreground font-medium">No academic staff registered</p>
                    </CardContent>
                  </Card>
                )}
              </div>
            )}
          </TabsContent>

          <TabsContent value="students" className="space-y-6">
            <div className="flex items-center justify-between">
              <div>
                <h2 className="text-2xl font-bold">Student Body</h2>
                <p className="text-muted-foreground">Directory of all active students and enrollment status</p>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {students.map((student) => {
                const enrollments = getEnrollments().filter(e => e.studentId === student.id && e.status === 'approved');
                return (
                  <Card key={student.id} className="border-primary/5 shadow-sm hover:shadow-lg transition-all">
                    <CardContent className="pt-8">
                      <div className="flex flex-col items-center text-center space-y-4">
                        <div className="w-20 h-20 rounded-full bg-primary/10 flex items-center justify-center border-4 border-white shadow-md">
                          {student.profilePic ? (
                            <img 
                              src={student.profilePic} 
                              alt={student.name}
                              className="w-full h-full rounded-full object-cover"
                            />
                          ) : (
                            <Users className="w-10 h-10 text-primary" />
                          )}
                        </div>
                        <div>
                          <p className="font-bold text-lg">{student.name}</p>
                          <p className="text-xs font-bold text-muted-foreground uppercase tracking-widest">ID: {student.id}</p>
                          <div className="flex gap-2 justify-center mt-2">
                            <span className="bg-primary/10 text-primary text-[10px] font-bold px-2 py-0.5 rounded-full uppercase">{student.program}</span>
                            <span className="bg-accent text-accent-foreground text-[10px] font-bold px-2 py-0.5 rounded-full uppercase">Year {student.year}</span>
                          </div>
                        </div>
                        <div className="pt-4 border-t w-full flex justify-between items-center px-4">
                          <span className="text-xs font-bold text-muted-foreground uppercase">Active Classes</span>
                          <span className="font-black text-primary">{enrollments.length}</span>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                );
              })}
              
              {students.length === 0 && (
                <Card className="col-span-full border-dashed border-2 bg-muted/20">
                  <CardContent className="flex flex-col items-center justify-center py-20">
                    <Users className="w-16 h-16 text-primary/20 mb-4" />
                    <p className="text-muted-foreground font-medium">No students currently registered</p>
                  </CardContent>
                </Card>
              )}
            </div>
          </TabsContent>
        </Tabs>
      </main>
    </div>
  );
}

function TeacherDetailsView({ teacher, subjects, onBack }: { teacher: User; subjects: Subject[]; onBack: () => void }) {
  const getEnrollmentCount = (subjectId: string) => {
    const enrollments = getEnrollments();
    return enrollments.filter(e => e.subjectId === subjectId).length;
  };

  return (
    <div className="space-y-6">
      <Button variant="ghost" onClick={onBack} className="text-primary hover:bg-primary/5">
        ← Back to Staff Directory
      </Button>

      <Card className="border-primary/10 overflow-hidden">
        <div className="h-24 bg-primary flex items-center px-8">
           <h2 className="text-2xl font-bold text-white">{teacher.name}</h2>
        </div>
        <CardHeader className="pb-4">
          <CardTitle className="text-lg">Staff Profile Details</CardTitle>
          <CardDescription className="flex items-center gap-4">
            <span className="font-bold text-primary">ID: {teacher.id}</span>
            <span className="text-muted-foreground">|</span>
            <span>{teacher.email}</span>
          </CardDescription>
        </CardHeader>
      </Card>

      <Card className="border-primary/10 shadow-lg">
        <CardHeader className="border-b bg-accent/30">
          <CardTitle className="text-lg font-bold">Assigned Subject Load ({subjects.length})</CardTitle>
        </CardHeader>
        <CardContent className="pt-6">
          {subjects.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground italic font-medium">No subjects currently assigned to this teacher</div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {subjects.map((subject) => (
                <div key={subject.id} className="p-5 border rounded-xl hover:border-primary/30 transition-all bg-white shadow-sm">
                  <h4 className="font-bold text-primary">{subject.name}</h4>
                  <p className="text-sm text-muted-foreground mt-1 flex items-center gap-1.5">
                    <School className="h-3.5 w-3.5" /> {subject.day} • {subject.time}
                  </p>
                  <div className="mt-4 flex items-center justify-between text-xs pt-3 border-t">
                    <span className="font-bold uppercase tracking-widest text-muted-foreground">Class Size</span>
                    <span className="font-black text-lg text-primary">{getEnrollmentCount(subject.id)}</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
