'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { Subject, getAttendances, Attendance } from '@/utils/storage';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { ArrowLeft, QrCode, User, BookOpen, Calendar as CalendarIcon, CheckCircle, XCircle, Clock } from 'lucide-react';
import { QRCodeSVG } from 'qrcode.react';

interface SubjectDetailsStudentProps {
  subject: Subject;
  onBack: () => void;
}

export default function SubjectDetailsStudent({ subject, onBack }: SubjectDetailsStudentProps) {
  const { user } = useAuth();
  const [showQR, setShowQR] = useState(false);
  const [attendances, setAttendances] = useState<Attendance[]>([]);

  useEffect(() => {
    const allAttendances = getAttendances();
    const myAttendances = allAttendances.filter(
      a => a.studentId === user?.id && a.subjectId === subject.id
    );
    setAttendances(myAttendances);
  }, [user, subject]);

  const qrData = `${user?.id}|${subject.id}`;

  const presentCount = attendances.filter(a => a.status === 'present').length;
  const lateCount = attendances.filter(a => a.status === 'late').length;
  const totalClasses = attendances.length;

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      <header className="bg-white border-b sticky top-0 z-10">
        <div className="container mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Button variant="ghost" onClick={onBack} size="icon">
              <ArrowLeft className="w-5 h-5" />
            </Button>
            <div>
              <h1 className="text-xl font-bold">{subject.name}</h1>
              <p className="text-xs text-muted-foreground uppercase font-bold tracking-widest">{subject.day} • {subject.time}</p>
            </div>
          </div>
          <Button 
            className="bg-[#E30613] hover:bg-[#E30613]/90 text-white font-bold rounded-full gap-2"
            onClick={() => setShowQR(!showQR)}
          >
            <QrCode className="h-4 w-4" /> {showQR ? 'Hide Code' : 'Mark Attendance'}
          </Button>
        </div>
      </header>

      <main className="container mx-auto px-4 py-8 space-y-8 max-w-5xl">
        <Card className="bg-[#E30613] text-white border-0 shadow-xl overflow-hidden relative rounded-3xl">
          <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl pointer-events-none" />
          <CardContent className="pt-10 pb-10 px-8 relative z-10">
            <div className="flex flex-col md:flex-row items-center gap-8">
              <div className="w-32 h-32 rounded-full bg-white/20 border-4 border-white/30 flex items-center justify-center overflow-hidden shadow-2xl">
                {user?.profilePic ? (
                  <img src={user.profilePic} alt={user.name} className="w-full h-full object-cover" />
                ) : (
                  <User className="w-16 h-16 text-white" />
                )}
              </div>
              <div className="flex-1 text-center md:text-left">
                <p className="text-[10px] font-black uppercase tracking-widest text-white/70">Student Enrollment Card</p>
                <h3 className="text-4xl font-black mt-1">{user?.name}</h3>
                <div className="flex flex-wrap justify-center md:justify-start gap-4 pt-4">
                  <div className="bg-white/10 px-4 py-2 rounded-xl border border-white/10">
                    <p className="text-[10px] font-black uppercase text-white/60">ID Number</p>
                    <p className="font-bold">{user?.id}</p>
                  </div>
                  <div className="bg-white/10 px-4 py-2 rounded-xl border border-white/10">
                    <p className="text-[10px] font-black uppercase text-white/60">Academic Level</p>
                    <p className="font-bold">Year {user?.year}</p>
                  </div>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        {showQR && (
          <Card className="border-primary shadow-2xl animate-in zoom-in-95 duration-300 rounded-3xl">
            <CardHeader className="bg-[#E30613] text-white rounded-t-3xl">
              <CardTitle className="flex items-center gap-2 text-lg">
                <QrCode className="w-5 h-5" />
                Digital Attendance ID
              </CardTitle>
            </CardHeader>
            <CardContent className="pt-10 pb-10 flex flex-col items-center">
              <div className="p-6 bg-white rounded-3xl shadow-xl border-4 border-primary/10">
                <QRCodeSVG value={qrData} size={240} level="H" includeMargin={false} fgColor="#E30613" />
              </div>
              <p className="mt-8 text-lg font-black text-center text-[#E30613] uppercase tracking-widest">Show this to your Instructor</p>
              <p className="text-sm text-muted-foreground text-center mt-2 max-w-sm">Scan this code at the start and end of class to log your presence.</p>
            </CardContent>
          </Card>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <Card className="border-primary/10 shadow-lg rounded-2xl">
            <CardHeader className="bg-accent/30 border-b">
              <CardTitle className="text-lg font-bold flex items-center gap-2">
                <BookOpen className="w-5 h-5 text-primary" />
                Subject Information
              </CardTitle>
            </CardHeader>
            <CardContent className="pt-6 space-y-4">
              <div>
                <p className="text-xs font-bold uppercase text-muted-foreground tracking-widest">Instructor</p>
                <p className="font-bold text-lg">{subject.teacherName}</p>
              </div>
              <div>
                <p className="text-xs font-bold uppercase text-muted-foreground tracking-widest">Current Schedule</p>
                <p className="font-bold text-lg">{subject.day} at {subject.time}</p>
              </div>
            </CardContent>
          </Card>

          <Card className="border-primary/10 shadow-lg rounded-2xl">
            <CardHeader className="bg-accent/30 border-b">
              <CardTitle className="text-lg font-bold flex items-center gap-2">
                <CalendarIcon className="w-5 h-5 text-primary" />
                Attendance Statistics
              </CardTitle>
            </CardHeader>
            <CardContent className="pt-6">
              <div className="grid grid-cols-3 gap-4">
                <div className="text-center p-4 rounded-2xl bg-green-50 border border-green-100">
                  <p className="text-[10px] font-bold uppercase text-green-600">Present</p>
                  <p className="text-3xl font-black text-green-700">{presentCount}</p>
                </div>
                <div className="text-center p-4 rounded-2xl bg-yellow-50 border border-yellow-100">
                  <p className="text-[10px] font-bold uppercase text-yellow-600">Late</p>
                  <p className="text-3xl font-black text-yellow-700">{lateCount}</p>
                </div>
                <div className="text-center p-4 rounded-2xl bg-red-50 border border-red-100">
                  <p className="text-[10px] font-bold uppercase text-red-600">Sessions</p>
                  <p className="text-3xl font-black text-red-700">{totalClasses}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      </main>
    </div>
  );
}
